-- Create "runtime_audit_events" table
CREATE TABLE "runtime_audit_events" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "event_type" character varying NOT NULL,
  "event_key" character varying NOT NULL DEFAULT '',
  "source" character varying NOT NULL DEFAULT 'server_bootstrap',
  "payload" character varying NOT NULL DEFAULT '{}',
  "created_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "runtimeauditevent_event_key_created_at" to table: "runtime_audit_events"
CREATE INDEX "runtimeauditevent_event_key_created_at" ON "runtime_audit_events" ("event_key", "created_at");
-- Create index "runtimeauditevent_event_type_created_at" to table: "runtime_audit_events"
CREATE INDEX "runtimeauditevent_event_type_created_at" ON "runtime_audit_events" ("event_type", "created_at");
-- Create "runtime_markers" table
CREATE TABLE "runtime_markers" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "marker_key" character varying NOT NULL,
  "marker_value" character varying NOT NULL DEFAULT '',
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "runtimemarker_marker_key" to table: "runtime_markers"
CREATE UNIQUE INDEX "runtimemarker_marker_key" ON "runtime_markers" ("marker_key");
